import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { showToast } from '../../utils/toast'
import { useAuth } from '../../context/AuthContext'
import { taskService, productService } from '../../services/api'
import PondChartCard from '../../components/charts/PondChartCard'
import '../../styles/technician/technician-tasks.css'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả trạng thái công việc' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
  { value: 'CANCELLED', label: 'Đã hủy' },
  { value: 'OVERDUE', label: 'Quá hạn' },
]

const TASK_TYPE_OPTIONS = [
  { value: '1', label: 'Xử lý ao (POND_PROCESS)' },
  { value: '2', label: 'Cho ăn (FEEDING)' },
  { value: '3', label: 'Cho thuốc (TREATMENT)' },
  { value: '4', label: 'Kiểm tra môi trường (ENVIRONMENTAL_CHECK)' },
  { value: '5', label: 'Thu hoạch (HARVEST)' },
  { value: '6', label: 'Công việc khác (OTHER)' },
]

const normalize = (v) => String(v || '').trim().toUpperCase()
const formatDate = (v) => (v ? new Date(v).toLocaleString('vi-VN') : '-')

const initialForm = {
  task_type: '2', // Mặc định ban đầu chọn Cho ăn (ID: 2) để an toàn dữ liệu
  task_title: '',
  description: '',
  start_date: '',
  due_date: '',
  product_id: '',
  quantity: '',
  assignments: [],
}

function TechnicianTasks() {
  const { user } = useAuth()
  const [tasks, setTasks] = useState([])
  const [matrixPonds, setMatrixPonds] = useState([])
  const [matrixWorkers, setMatrixWorkers] = useState([])
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(false)

  // Filter states
  const [filterStatus, setFilterStatus] = useState('ALL')
  const [filterType, setFilterType] = useState('ALL')
  const [searchTerm, setSearchTerm] = useState('')

  // Modal states
  const [selectedTask, setSelectedTask] = useState(null)
  const [isCreateOpen, setIsCreateOpen] = useState(false)
  const [form, setForm] = useState(initialForm)

  // 1. Tải danh sách công việc chung hiển thị lên bảng biểu
  const fetchTasks = useCallback(async () => {
    try {
      const res = await taskService.getAllTasks()
      if (res.data?.success) {
        setTasks(res.data.data || [])
      }
    } catch (err) {
      console.error(err)
      showToast({ title: 'Không thể nạp danh sách công việc', type: 'error' })
    }
  }, [])

  // 2. FIXED: Tải danh sách ao nuôi ma trận lọc THOẢ MÃN ĐÚNG TRẠNG THÁI + TYPE_ID gửi lên Backend
  const fetchMatrixPonds = useCallback(async (currentTaskType) => {
    try {
      const numericTypeId = parseInt(currentTaskType, 10)
      if (isNaN(numericTypeId)) return

      // Truyền param chuẩn xác qua query string để kích hoạt bộ lọc phân nhánh thông minh tại Backend
      const res = await taskService.getPondsForTask({ params: { type_id: numericTypeId } })
      if (res.data?.success) {
        setMatrixPonds(res.data.data || [])
      }
    } catch (err) {
      console.error(err)
      showToast({ title: 'Lỗi nạp danh sách ao theo trạng thái nghiệp vụ', type: 'error' })
    }
  }, [])

  // 3. Tải danh sách công nhân để lập ma trận giao việc phối hợp
  const fetchMatrixWorkers = useCallback(async () => {
    try {
      const res = await taskService.getWorkersForTask()
      if (res.data?.success) {
        setMatrixWorkers(res.data.data || [])
      }
    } catch (err) {
      console.error(err)
    }
  }, [])

  // 4. Tải danh mục vật tư sản phẩm kho
  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getAllProducts ? await productService.getAllProducts() : { data: { success: true, data: [] } }
      if (res.data?.success) {
        setProducts(res.data.data || [])
      }
    } catch (err) {
      console.error(err)
    }
  }, [])

  // Khởi chạy nạp tài nguyên ban đầu khi component gắn vào cây DOM
  useEffect(() => {
    fetchTasks()
    fetchMatrixWorkers()
    fetchProducts()
  }, [fetchTasks, fetchMatrixWorkers, fetchProducts])

  // AUTO RE-LOAD MA TRẬN AO NUÔI KHI KỸ SƯ THAY ĐỔI LOẠI CÔNG VIỆC TRÊN DROPDOWN FORM TẠO VIỆC
  useEffect(() => {
    if (isCreateOpen && form.task_type) {
      fetchMatrixPonds(form.task_type)
      // Reset ma trận đã tích chọn trước đó nhằm tránh rác dữ liệu sai ao
      setForm(prev => ({ ...prev, assignments: [] }))
    }
  }, [form.task_type, isCreateOpen, fetchMatrixPonds])

  // Kiểm tra loại công việc hiện tại có cần hiển thị ô chỉ định vật tư hay không
  const isProductRequired = useMemo(() => {
    const t = parseInt(form.task_type, 10)
    return [1, 2, 3].includes(t) // 1: Xử lý ao, 2: Cho ăn, 3: Cho thuốc
  }, [form.task_type])

  // Đếm dữ liệu tổng quan thống kê (Đồng bộ Class với shared-stats.css)
  const stats = useMemo(() => {
    const total = tasks.length
    let pending = 0, progress = 0, completed = 0, overdue = 0
    tasks.forEach((t) => {
      const s = normalize(t.status)
      if (s === 'PENDING') pending++
      else if (s === 'IN_PROGRESS' || s === 'DOING') progress++
      else if (s === 'COMPLETED' || s === 'DONE') completed++
      else if (s === 'OVERDUE') overdue++
    })
    return { total, pending, progress, completed, overdue }
  }, [tasks])

  // Bộ lọc dữ liệu hiển thị trên bảng Table danh sách
  const filteredTasks = useMemo(() => {
    return tasks.filter((t) => {
      const matchStatus = filterStatus === 'ALL' || normalize(t.status) === normalize(filterStatus)
      const matchType = filterType === 'ALL' || String(t.type_id) === String(filterType)
      const txt = searchTerm.trim().toLowerCase()
      const matchText =
        !txt ||
        (t.task_code || '').toLowerCase().includes(txt) ||
        (t.task_title || '').toLowerCase().includes(txt) ||
        (t.pond_name || '').toLowerCase().includes(txt)
      return matchStatus && matchType && matchText
    })
  }, [tasks, filterStatus, filterType, searchTerm])

  // Xử lý bật/tắt các ô giao điểm tương tác trên ma trận phân phối việc
  const handleToggleMatrix = (pondId, workerId) => {
    const idx = form.assignments.findIndex(
      (a) => Number(a.pond_id) === Number(pondId) && Number(a.worker_id) === Number(workerId)
    )
    let newAssigns = [...form.assignments]
    if (idx > -1) {
      newAssigns.splice(idx, 1)
    } else {
      newAssigns.push({ pond_id: pondId, worker_id: workerId })
    }
    setForm({ ...form, assignments: newAssigns })
  }

  // FIXED: Logic kích hoạt phát lệnh tạo chuỗi công việc ma trận độc lập
  const handleCreateTask = async () => {
    if (!form.assignments || form.assignments.length === 0) {
      showToast({ title: 'Vui lòng chọn ít nhất một ô giao điểm trên ma trận phân công', type: 'warning' })
      return
    }
    if (!form.description?.trim()) {
      showToast({ title: 'Vui lòng nhập hướng dẫn kỹ thuật / mô tả nghiệp vụ không được để trống', type: 'warning' })
      return
    }

    const confirmAction = window.confirm(`Xác nhận khởi tạo đồng loạt ${form.assignments.length} nhiệm vụ độc lập trên hệ thống ma trận?`)
    if (!confirmAction) return

    setLoading(true)
    try {
      let finalTitle = form.task_title?.trim()
      if (!finalTitle) {
        const typeOpt = TASK_TYPE_OPTIONS.find((o) => o.value === form.task_type)
        finalTitle = typeOpt ? `Công tác ${typeOpt.label.split(' (')[0]}` : 'Công việc kỹ thuật ao'
      }

      const numericTypeId = parseInt(form.task_type, 10)

      // Vòng lặp bắn lệnh tuần tự tạo task cho từng ô đã tích chọn phối hợp
      for (const assignment of form.assignments) {
        const selectedPondObj = matrixPonds.find((p) => Number(p.pond_id) === Number(assignment.pond_id))

        const singleTaskData = {
          type_id: numericTypeId,             // Kiểm soát chặt kiểu số nguyên khóa ngoại
          pond_id: Number(assignment.pond_id), // Ép kiểu ID ao nuôi
          task_title: finalTitle,
          description: form.description.trim(),
          start_date: form.start_date || new Date().toISOString(),
          due_date: form.due_date,
          assigned_workers: [Number(assignment.worker_id)], // Đưa ID công nhân vào mảng
        }

        // Đính kèm ID mùa vụ nếu ao đang chạy trong chu kỳ nuôi tích cực
        if (selectedPondObj?.season_id) {
          singleTaskData.season_id = Number(selectedPondObj.season_id)
        }

        // Hạch toán vật tư nếu thuộc nhóm tiêu hao
        if (isProductRequired && form.product_id) {
          singleTaskData.product_id = Number(form.product_id)
          singleTaskData.quantity = parseFloat(form.quantity) || 0
        }

        await taskService.createTask(singleTaskData)
      }

      showToast({ title: `Đã kích hoạt triển khai thành công ${form.assignments.length} công việc thực địa!`, type: 'success' })
      setForm(initialForm)
      setIsCreateOpen(false)
      await fetchTasks()
    } catch (err) {
      const errorMsg = err.response?.data?.error || err.response?.data?.message || 'Lỗi xử lý cơ sở dữ liệu'
      showToast({ title: 'Không thể tạo công việc ma trận: ' + errorMsg, type: 'error' })
    } finally {
      setLoading(false)
    }
  }

  // Hủy bỏ bản ghi công việc (Chỉ khả dụng khi trạng thái đang là PENDING)
  const handleCancelTask = async (taskId) => {
    if (!window.confirm('Bạn có chắc chắn muốn hủy bỏ hoàn toàn công việc này không?')) return
    try {
      const res = await taskService.cancelTask ? await taskService.cancelTask(taskId) : null
      if (res && res.data?.success) {
        showToast({ title: 'Đã hủy bỏ công việc thành công', type: 'success' })
        setSelectedTask(null)
        await fetchTasks()
      } else {
        showToast({ title: 'Không thể thực hiện hủy (Yêu cầu API cancelTask)', type: 'warning' })
      }
    } catch (err) {
      showToast({ title: 'Lỗi hệ thống khi hủy công việc', type: 'error' })
    }
  }

  // Hàm tính toán trạng thái tổng quan ngầm định hỗ trợ hiển thị badge màu sắc sinh động
  const getComputedStatus = (task) => {
    if (!task) return 'PENDING'
    const s = normalize(task.status)
    if (s === 'COMPLETED' || s === 'DONE') return 'COMPLETED'
    if (s === 'CANCELLED') return 'CANCELLED'
    if (s === 'OVERDUE') return 'OVERDUE'
    if (new Date(task.due_date) < new Date() && s !== 'COMPLETED') return 'OVERDUE'
    if (s === 'IN_PROGRESS' || s === 'DOING') return 'IN_PROGRESS'
    return 'PENDING'
  }

  const getStatusLabel = (st) => {
    const found = STATUS_OPTIONS.find((o) => o.value === st)
    return found ? found.label : st
  }

  const getStatusBadgeClass = (task) => {
    const cs = getComputedStatus(task)
    if (cs === 'COMPLETED') return 'task-status task-status--done'
    if (cs === 'IN_PROGRESS') return 'task-status task-status--progress'
    if (cs === 'CANCELLED') return 'task-status task-status--cancelled'
    if (cs === 'OVERDUE') return 'task-status task-status--overdue'
    return 'task-status task-status--pending'
  }

  return (
    <div className="technician-tasks technician-seasons_page">
      <div className="technician-seasons_header">
        <h2 className="technician-seasons_title">Quản lý Tiến độ Công việc Kỹ thuật</h2>
        <button type="button" className="btn btn-primary" onClick={() => setIsCreateOpen(true)}>
          + Phân phối việc hệ Ma trận
        </button>
      </div>

      {/* --- CỤM THỐNG KÊ TỔNG QUAN ĐỒNG BỘ 100% SHARED-STATS.CSS --- */}
      <div className="stats-grid">
        <div className="stats-card stats-card--neutral">
          <span className="stats-card-label">Tổng công việc</span>
          <strong className="stats-card-value">{stats.total}</strong>
        </div>
        <div className="stats-card stats-card--warning">
          <span className="stats-card-label">Chờ xử lý</span>
          <strong className="stats-card-value">{stats.pending}</strong>
        </div>
        <div className="stats-card stats-card--primary">
          <span className="stats-card-label">Đang thực hiện</span>
          <strong className="stats-card-value">{stats.progress}</strong>
        </div>
        <div className="stats-card stats-card--success">
          <span className="stats-card-label">Hoàn thành</span>
          <strong className="stats-card-value">{stats.completed}</strong>
        </div>
        <div className="stats-card stats-card--danger">
          <span className="stats-card-label">Quá hạn</span>
          <strong className="stats-card-value">{stats.overdue}</strong>
        </div>
      </div>

      {/* --- BỘ LỌC TÌM KIẾM --- */}
      <div className="technician-seasons_filters" style={{ marginTop: '20px' }}>
        <input
          type="text"
          className="search-input-base"
          placeholder="Tìm kiếm nhanh mã việc, tên công việc, tên ao..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
        <select className="filter-select-base" value={filterStatus} onChange={(e) => setFilterStatus(e.target.value)}>
          {STATUS_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </select>
        <select className="filter-select-base" value={filterType} onChange={(e) => setFilterType(e.target.value)}>
          <option value="ALL">Tất cả loại hình nghiệp vụ</option>
          {TASK_TYPE_OPTIONS.map((o) => (
            <option key={o.value} value={o.value}>
              {o.label.split(' (')[0]}
            </option>
          ))}
        </select>
      </div>

      {/* --- BẢNG DANH SÁCH CÔNG VIỆC CHÍNH --- */}
      <div className="technician-seasons_table-container" style={{ marginTop: '16px' }}>
        <table className="technician-seasons_table">
          <thead>
            <tr>
              <th>Mã công việc</th>
              <th>Ao nuôi</th>
              <th>Tiêu đề công việc</th>
              <th>Loại nghiệp vụ</th>
              <th>Hạn hoàn thành</th>
              <th>Trạng thái tổng</th>
              <th style={{ textAlign: 'center' }}>Thao tác</th>
            </tr>
          </thead>
          <tbody>
            {filteredTasks.length > 0 ? (
              filteredTasks.map((t) => {
                const computedSt = getComputedStatus(t)
                const typeOpt = TASK_TYPE_OPTIONS.find((o) => String(o.value) === String(t.type_id))
                return (
                  <tr key={`task-row-${t.task_id}`}>
                    <td style={{ fontWeight: '600', color: '#0284c7' }}>{t.task_code || `ID: ${t.task_id}`}</td>
                    <td>
                      <strong>{t.pond_name || `Ao ID: ${t.pond_id}`}</strong>
                    </td>
                    <td>{t.task_title}</td>
                    <td>
                      <span className="task-type-label-tag">{t.type_name || typeOpt?.label.split(' (')[0] || 'Khác'}</span>
                    </td>
                    <td>{formatDate(t.due_date)}</td>
                    <td>
                      <span className={getStatusBadgeClass(t)}>{getStatusLabel(computedSt)}</span>
                    </td>
                    <td style={{ textAlign: 'center' }}>
                      <button type="button" className="btn btn-secondary btn-sm" onClick={() => setSelectedTask(t)}>
                        Xem chi tiết
                      </button>
                    </td>
                  </tr>
                )
              })
            ) : (
              <tr>
                <td colSpan="7" style={{ textAlign: 'center', padding: '24px', color: '#64748b', fontStyle: 'italic' }}>
                  Không tìm thấy dữ liệu công việc kỹ thuật nào thoả mãn bộ lọc.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* ==========================================================================
         MODAL XEM CHI TIẾT CÔNG VIỆC CHUẨN GRID - ĐỒNG BỘ 100% POND/SEASON (TRỪ CHI PHÍ)
         ========================================================================== */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content technician-seasons_modal" style={{ maxWidth: '800px' }} onClick={(e) => e.stopPropagation()}>
            <h3 className="technician-seasons_modal-title">Chi tiết tiến độ công việc</h3>

            <div className="technician-seasons_detail-grid">
              <div>
                <strong>Mã công việc (task_code):</strong>
                <p style={{ color: '#0284c7', fontWeight: '600' }}>{selectedTask.task_code || '-'}</p>
              </div>
              <div>
                <strong>Loại công việc (task_types):</strong>
                <p><strong>{selectedTask.type_name || selectedTask.task_type || '-'}</strong></p>
              </div>
              
              <div style={{ gridColumn: '1 / -1' }}>
                <strong>Tiêu đề công việc (task_title):</strong>
                <p style={{ fontWeight: '500', color: '#1e293b' }}>{selectedTask.task_title || '-'}</p>
              </div>

              <div>
                <strong>Ao nuôi thực hiện (pond_id):</strong>
                <p>{selectedTask.pond_name || '-'} {selectedTask.pond_code ? `(${selectedTask.pond_code})` : ''}</p>
              </div>
              <div>
                <strong>Thuộc mùa vụ (season_id):</strong>
                <p>{selectedTask.season_name || 'Công việc chung (Không gắn với mùa vụ)'}</p>
              </div>

              <div>
                <strong>Thời gian bắt đầu kế hoạch (start_date):</strong>
                <p>{formatDate(selectedTask.start_date)}</p>
              </div>
              <div>
                <strong>Hạn chót hoàn thành (due_date):</strong>
                <p>{formatDate(selectedTask.due_date)}</p>
              </div>

              <div>
                <strong>Kỹ sư giao việc (assigned_by):</strong>
                <p>{selectedTask.creator_name || `Kỹ sư hệ thống (ID: ${selectedTask.assigned_by})`}</p>
              </div>
              <div>
                <strong>Trạng thái công việc tổng (status):</strong>
                <p style={{ marginTop: '4px' }}>
                  <span className={getStatusBadgeClass(selectedTask)}>
                    {getStatusLabel(getComputedStatus(selectedTask))}
                  </span>
                </p>
              </div>

              <div>
                <strong>Ngày tạo bản ghi (created_at):</strong>
                <p style={{ color: '#64748b', fontSize: '0.85rem' }}>{formatDate(selectedTask.created_at)}</p>
              </div>
              <div>
                <strong>Cập nhật cuối lúc (updated_at):</strong>
                <p style={{ color: '#64748b', fontSize: '0.85rem' }}>{formatDate(selectedTask.updated_at)}</p>
              </div>

              {/* KHỐI VẬT TƯ: BẢO MẬT TUYỆT ĐỐI KHÔNG HIỂN THỊ CHI PHÍ ĐƠN GIÁ, THÀNH TIỀN */}
              {selectedTask.product_info ? (
                <div style={{ gridColumn: '1 / -1', background: '#f0f9ff', borderColor: '#bae6fd' }}>
                  <strong style={{ color: '#0369a1' }}>Vật tư chỉ định sử dụng (task_product_usage):</strong>
                  <p style={{ marginTop: '6px', color: '#1e293b' }}>
                    Sản phẩm: <strong style={{ color: '#0369a1' }}>{selectedTask.product_info.product_name}</strong> 
                    &nbsp;—&nbsp; Số lượng định mức (quantity): <strong style={{ color: '#0284c7', fontSize: '1.05rem' }}>{selectedTask.product_info.quantity}</strong> {selectedTask.product_info.unit || ''}
                  </p>
                </div>
              ) : (
                <div style={{ gridColumn: '1 / -1', background: '#f8fafc', borderStyle: 'dashed', color: '#64748b' }}>
                  <span style={{ fontSize: '0.85rem', fontStyle: 'italic' }}>Công việc này không yêu cầu xuất vật tư từ kho đi kèm.</span>
                </div>
              )}

              {/* CHI TIẾT TIẾN ĐỘ THỰC ĐỊA CỦA TỪNG CÔNG NHÂN (BẢNG task_workers) */}
              <div style={{ gridColumn: '1 / -1', background: '#fcf8f2', borderColor: '#fed7aa' }}>
                <strong style={{ color: '#c2410c' }}>Chi tiết phân công & Tiến độ thực tế của Công nhân (task_workers):</strong>
                <div style={{ marginTop: '8px', display: 'flex', flexDirection: 'column', gap: '8px' }}>
                  {selectedTask.assigned_workers_list && selectedTask.assigned_workers_list.length > 0 ? (
                    selectedTask.assigned_workers_list.map((worker, idx) => (
                      <div key={`detail-worker-${worker.worker_id || idx}`} style={{ background: '#ffffff', padding: '10px 14px', borderRadius: '8px', border: '1px solid #ffedd5' }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                          <strong>Công nhân phụ trách: <span style={{ color: '#ea580c', fontSize: '0.95rem' }}>{worker.full_name}</span></strong>
                          <span style={{ 
                            fontSize: '11px', 
                            padding: '3px 10px', 
                            borderRadius: '20px', 
                            background: worker.worker_status === 'DONE' ? '#d1fae5' : '#fef3c7', 
                            color: worker.worker_status === 'DONE' ? '#065f46' : '#d97706', 
                            fontWeight: '600' 
                          }}>
                            {worker.worker_status || 'ASSIGNED'}
                          </span>
                        </div>
                        
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px', marginTop: '8px', fontSize: '0.85rem', color: '#475569' }}>
                          <div>⏱ Nhận việc thực tế (started_at): <span style={{ color: '#0f172a', fontWeight: '500' }}>{formatDate(worker.started_at)}</span></div>
                          <div>✓ Bấm xong thực tế (completed_at): <span style={{ color: '#0f172a', fontWeight: '500' }}>{formatDate(worker.completed_at)}</span></div>
                        </div>

                        {worker.note && (
                          <div style={{ marginTop: '8px', padding: '6px 10px', background: '#f8fafc', borderRadius: '6px', borderLeft: '3px solid #cbd5e1', fontSize: '0.85rem', color: '#334155' }}>
                            <strong>Báo cáo/Ghi chú từ công nhân (note):</strong> {worker.note}
                          </div>
                        )}
                      </div>
                    ))
                  ) : (
                    <p style={{ color: '#ef4444', fontStyle: 'italic', margin: 0, fontSize: '0.85rem' }}>Chưa cấu hình danh sách công nhân phụ trách.</p>
                  )}
                </div>
              </div>

              <div style={{ gridColumn: '1 / -1' }}>
                <strong>Hướng dẫn kỹ thuật / Mô tả nghiệp vụ (description):</strong>
                <p className="technical-instruction-text" style={{ whiteSpace: 'pre-line', color: '#334155', background: '#ffffff', padding: '12px', borderRadius: '8px', border: '1px solid #cbd5e1', marginTop: '6px', lineHeight: '1.5', fontSize: '0.9rem' }}>
                  {selectedTask.description || 'Không có mô tả hoặc hướng dẫn cụ thể.'}
                </p>
              </div>
            </div>

            {/* MINH CHỨNG HÌNH ẢNH THỰC ĐỊA */}
            {selectedTask.task_images && selectedTask.task_images.length > 0 && (
              <div style={{ marginTop: '16px', padding: '0 4px' }}>
                <span style={{ fontWeight: '600', fontSize: '0.85rem', color: '#475569' }}>Hình ảnh minh chứng thực địa (task_images):</span>
                <div style={{ display: 'flex', gap: '12px', marginTop: '8px', flexWrap: 'wrap' }}>
                  {selectedTask.task_images.map((imgUrl, i) => (
                    <img 
                      key={`task-img-view-${i}`} 
                      src={imgUrl} 
                      alt={`Báo cáo thực địa ${i + 1}`} 
                      style={{ width: '90px', height: '90px', objectFit: 'cover', borderRadius: '8px', border: '1px solid #cbd5e1', cursor: 'pointer', transition: 'transform 0.2s' }} 
                      onClick={() => window.open(imgUrl, '_blank')}
                      onMouseEnter={(e) => e.target.style.transform = 'scale(1.05)'}
                      onMouseLeave={(e) => e.target.style.transform = 'scale(1)'}
                    />
                  ))}
                </div>
              </div>
            )}

            <div className="technician-seasons_actions" style={{ marginTop: '24px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <div>
                {normalize(selectedTask.status) === 'PENDING' && (
                  <button type="button" className="btn btn-danger" onClick={() => handleCancelTask(selectedTask.task_id)}>
                    Hủy bỏ công việc
                  </button>
                )}
              </div>
              <button type="button" className="btn btn-secondary" onClick={() => setSelectedTask(null)}>Đóng hộp thoại</button>
            </div>
          </div>
        </div>
      )}

      {/* ==========================================================================
         MODAL LẬP PHÂN PHỐI CÔNG VIỆC THEO HỆ THỐNG MA TRẬN PHỐI HỢP DÂN SỰ
         ========================================================================== */}
      {isCreateOpen && (
        <div className="modal" onClick={() => setIsCreateOpen(false)}>
          <div className="modal-content technician-seasons_modal" style={{ maxWidth: '900px' }} onClick={(e) => e.stopPropagation()}>
            <h3 className="technician-seasons_modal-title">Bảng phân phối công việc hệ Ma trận</h3>

            <div className="technician-seasons_form-container">
              
              <div className="technician-seasons_form-row">
                <div className="technician-seasons_input-group">
                  <label className="technician-seasons_input-label">Mẫu loại nghiệp vụ <span style={{ color: 'red' }}>*</span></label>
                  <select 
                    className="technician-seasons_input-field" 
                    value={form.task_type} 
                    onChange={(e) => setForm({ ...form, task_type: e.target.value })}
                  >
                    {TASK_TYPE_OPTIONS.map((o) => (
                      <option key={o.value} value={o.value}>{o.label}</option>
                    ))}
                  </select>
                </div>
                <div className="technician-seasons_input-group">
                  <label className="technician-seasons_input-label">Tiêu đề (Để trống sẽ tự sinh mặc định)</label>
                  <input 
                    type="text" 
                    className="technician-seasons_input-field" 
                    placeholder="Ví dụ: Cấp cám cử sáng, Tháo nước khử trùng..." 
                    value={form.task_title} 
                    onChange={(e) => setForm({ ...form, task_title: e.target.value })}
                  />
                </div>
              </div>

              {/* PHÂN HỆ VẬT TƯ TIÊU HAO KHO (KHI CHỌN LOẠI 1, 2, 3) */}
              {isProductRequired && (
                <div className="technician-seasons_harvest-box" style={{ background: '#f0f9ff', borderColor: '#bae6fd', marginTop: '4px' }}>
                  <span style={{ fontWeight: '600', color: '#0369a1', display: 'block', marginBottom: '8px', fontSize: '0.9rem' }}>
                    📦 Định mức cấp phát vật tư kho kèm theo (Chỉ áp dụng với Xử lý ao, Cho ăn, Cho thuốc)
                  </span>
                  <div className="technician-seasons_form-row" style={{ marginBottom: 0 }}>
                    <div className="technician-seasons_input-group">
                      <label className="technician-seasons_input-label" style={{ color: '#0369a1' }}>Chọn sản phẩm trong kho vật tư</label>
                      <select 
                        className="technician-seasons_input-field" 
                        value={form.product_id} 
                        onChange={(e) => setForm({ ...form, product_id: e.target.value })}
                      >
                        <option value="">-- Không yêu cầu xuất kho cấp phát vật tư --</option>
                        {products.map((p) => (
                          <option key={p.product_id} value={p.product_id}>
                            {p.product_name} ({p.unit || 'Đơn vị'}) - Tồn: {p.stock_quantity ?? 'N/A'}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div className="technician-seasons_input-group">
                      <label className="technician-seasons_input-label" style={{ color: '#0369a1' }}>Số lượng chỉ định sử dụng</label>
                      <input 
                        type="number" 
                        step="any"
                        className="technician-seasons_input-field" 
                        placeholder="Nhập định mức lượng cấp phát..." 
                        value={form.quantity} 
                        onChange={(e) => setForm({ ...form, quantity: e.target.value })}
                        disabled={!form.product_id}
                      />
                    </div>
                  </div>
                </div>
              )}

              {/* GIAO DIỆN KHU VỰC MA TRẬN PHỐI HỢP THỰC ĐỊA */}
              <div style={{ marginTop: '16px' }}>
                <label className="technician-seasons_input-label" style={{ marginBottom: '8px', display: 'block' }}>
                  Ma trận liên kết Ao nuôi & Nhân lực phụ trách <span style={{ color: 'red' }}>*</span> 
                  <span style={{ color: '#64748b', fontWeight: 'normal', fontSize: '0.8rem' }}> (Tích chọn ô giao điểm để tạo công việc)</span>
                </label>
                
                <div style={{ width: '100%', overflowX: 'auto', border: '1px solid #e5e7eb', borderRadius: '8px' }}>
                  <table className="matrix-table-base">
                    <thead>
                      <tr>
                        <th className="matrix-th-pond" style={{ background: '#f3f4f6' }}>Danh sách Ao nuôi điều tiết</th>
                        {matrixWorkers.map((w) => (
                          <th key={`th-worker-${w.user_id}`} className="matrix-th-worker" style={{ background: '#f3f4f6', minWidth: '110px' }}>
                            <div className="worker-info-cell">
                              <span>{w.full_name}</span>
                              <span className="worker-usernames-sub">@{w.username}</span>
                            </div>
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {matrixPonds.length > 0 ? (
                        matrixPonds.map((p) => (
                          <tr key={`tr-pond-${p.pond_id}`}>
                            <td className="matrix-th-pond" style={{ fontWeight: '600' }}>
                              <div>{p.pond_name} <span style={{ color: '#64748b', fontSize: '0.75rem' }}>({p.pond_code})</span></div>
                              <div style={{ fontSize: '11px', color: p.season_id ? '#16a34a' : '#d97706', marginTop: '2px' }}>
                                {p.season_id ? `✓ Đang chạy Mùa vụ ID: ${p.season_id}` : '• Trạng thái Ao trống/Xử lý'}
                              </div>
                            </td>
                            {matrixWorkers.map((w) => {
                              const isChecked = form.assignments.some(
                                (a) => Number(a.pond_id) === Number(p.pond_id) && Number(a.worker_id) === Number(w.user_id)
                              )
                              return (
                                <td 
                                  key={`intersect-${p.pond_id}-${w.user_id}`}
                                  className={`matrix-cell-intersect ${isChecked ? 'cell-active' : ''}`}
                                  onClick={() => handleToggleMatrix(p.pond_id, w.user_id)}
                                >
                                  {isChecked ? '✓ ĐÃ CHỌN' : '+'}
                                </td>
                              )
                            })}
                          </tr>
                        ))
                      ) : (
                        <tr>
                          <td colSpan={matrixWorkers.length + 1} style={{ textAlign: 'center', padding: '20px', color: '#64748b', fontStyle: 'italic' }}>
                            Không tìm thấy ao nuôi nào thoả mãn bộ lọc nghiệp vụ hiện tại.
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>

              <div style={{ marginTop: '14px' }}>
                <label className="technician-seasons_input-label">Hướng dẫn kỹ thuật / Nhật ký chỉ định thao tác thực địa <span style={{ color: 'red' }}>*</span></label>
                <textarea 
                  className="technician-seasons_input-field" 
                  rows="3" 
                  style={{ height: 'auto', padding: '10px' }}
                  placeholder="Yêu cầu ghi chi tiết lưu ý kỹ thuật (Ví dụ: Cho ăn từ từ tránh thất thoát, rải vôi quanh bờ viền ao...)"
                  value={form.description} 
                  onChange={(e) => setForm({ ...form, description: e.target.value })}
                />
              </div>

              <div className="technician-seasons_form-row" style={{ marginTop: '14px' }}>
                <div className="technician-seasons_input-group">
                  <label className="technician-seasons_input-label">Thời gian bắt đầu <span style={{ color: 'red' }}>*</span></label>
                  <input type="datetime-local" className="technician-seasons_input-field" value={form.start_date} onChange={(e) => setForm({ ...form, start_date: e.target.value })} />
                </div>
                <div className="technician-seasons_input-group">
                  <label className="technician-seasons_input-label">Hạn chót hoàn thành <span style={{ color: 'red' }}>*</span></label>
                  <input type="datetime-local" className="technician-seasons_input-field" value={form.due_date} onChange={(e) => setForm({ ...form, due_date: e.target.value })} />
                </div>
              </div>

            </div>

            <div className="technician-seasons_actions" style={{ marginTop: '24px' }}>
              <button type="button" className="btn btn-secondary" onClick={() => setIsCreateOpen(false)}>Hủy bỏ</button>
              <button
                type="button"
                className="btn btn-primary"
                onClick={handleCreateTask}
                disabled={loading || form.assignments.length === 0 || !form.start_date || !form.due_date}
              >
                {loading ? 'Đang kích hoạt...' : `Kích hoạt ${form.assignments.length} công việc`}
              </button>
            </div>
          </div>
        </div>
      )}

    </div>
  )
}

export default TechnicianTasks
